INSERT INTO `products` (`id`, `name`, `slug`, `sku`, `type`, `category_id`, `brand_id`, `category`, `price`, `sale_price`, `wholesale_price`, `sale_wholesale_price`, `image`, `description`, `short_description`, `tags`, `is_featured`, `is_active`, `weight`, `meta_title`, `meta_description`, `badge`, `in_stock`, `stock_quantity`, `low_stock_threshold`, `manage_stock`, `allow_backorder`, `min_wholesale_qty`, `created_at`, `updated_at`) VALUES
(273, 'Climbing Rose \'Eden\' Starter Plant Fragrant Large Pink Cream Cupped Flowers---Stunning!!', 'climbing-rose-eden-starter-plant-fragrant-large-pink-cream-cupped-flowers-stunning', 'ETSY-0001', 'simple', 9, NULL, 'Roses', 27.90, NULL, 16.74, NULL, 'https://i.etsystatic.com/20088520/r/il/4ea3de/6065602161/il_fullxfull.6065602161_gn5m.jpg', 'WE CANNOT SHIP TO THE FOLLOWING STATES DUE TO SHIPPING RESTRICTIONS: CALIFORNIA, OREGON, WASHINGTON, ARIZONA, ALASKA, HAWAII, IDAHO AND NEVADA\n**WE CANNOT SHIP TO P.O. BOXES!!**\nSECOND PICTURE IS A REPRESENTATION OF THE PLANT YOU WILL RECEIVE.\n***ITEMS ARE TAPED IN THE BOX FOR SECURE SHIPPING. PLEASE BE CAREFUL TO REMOVE TAPE FIRST BEFORE REMOVING PLANT(S)***\n\nThis listing is for 1 live starter plant that is 3\" - 6\" tall and growing quickly in a quart pot! This climber is absolutely gorgeous! In late Spring, it explodes with numerous large and lightly fragrant pink and cream flowers that are cupped and globular shaped! Each flower has 55 to 65 petals that give it a layered look! It will rebloom through the season, but the first flush of flowers is the most prolific! Grow these on a arch or pillar to make a dreamy statement in your garden!!\n\nCommon Name: \'Eden\' Climbing Rose\nBotanical Name: Rosa \'Pierre de Ronsard\'\nHardiness Zones: 5 - 9\nBloom Time: Spring\nSunlight: Full sun\nSoil Requirements: Moist, well drained soil\nMature Size: 6\' to 10\' tall \nBloom Color: Pink and cream\nEvergreen or Deciduous: Deciduous', '1 live starter plant that is 3\" - 6\" tall and growing quickly in a quart pot! This climber is absolutely gorgeous! In late Spring, it explodes with numerous large and lightly fragrant pink and cream flowers that are cupp...', '[\"Fragrant Flowers\",\"Reblooming Rose\",\"Unique Flowers\",\"Showy Flowers\",\"Cottage Garden\",\"Numerous Petals\",\"Romantic Look\",\"Climbs Pillars\",\"Short Climber\",\"Climbs Archs\",\"Climbs Fences\",\"Disease Resistant\",\"Vigorous Growth\"]', 1, 1, NULL, NULL, NULL, NULL, 1, 5, 5, 1, 0, 5, '2026-06-24 16:08:57', '2026-06-24 16:08:57'),
(274, 'Arborose Tangerine Skies Climbing Rose Starter Plant: Fragrant Orange Flowers', 'arborose-tangerine-skies-climbing-rose-starter-plant-fragrant-orange-flowers', 'ETSY-0002', 'simple', 9, NULL, 'Roses', 27.90, NULL, 16.74, NULL, 'https://i.etsystatic.com/20088520/r/il/f41375/8049194155/il_fullxfull.8049194155_c1lb.jpg', 'WE CANNOT SHIP TO THE FOLLOWING STATES DUE TO SHIPPING RESTRICTIONS: CALIFORNIA, OREGON, WASHINGTON, ARIZONA, ALASKA, HAWAII, IDAHO AND NEVADA\n**WE CANNOT SHIP TO P.O. BOXES!!**\nSECOND PICTURE IS A REPRESENTATION OF THE PLANT YOU WILL RECEIVE.\n***ITEMS ARE TAPED IN THE BOX FOR SECURE SHIPPING. PLEASE BE CAREFUL TO REMOVE TAPE FIRST BEFORE REMOVING PLANT(S)***\n\nThis listing is for 1 live starter plant that is 3\" - 6\" tall and growing quickly in a quart pot! This is another beautiful climbing Rose that is very robust and winter-hardy! In Spring, it starts blooming with fragrant flowers that are orange! It also blooms continuously through Summer and well into Fall! It is mostly used as a climbing arbors, trellis, fences and pergolas. \n\nCommon Name: \'Arborose Tangerine Skies\' Climbing Rose\nBotanical Name: Rosa \'KORtangenu\' PP 30,588\nHardiness Zones: 5 - 9\nBloom Time: Spring through Fall\nSunlight: Full sun\nSoil Requirements: Moist, well drained soil\nMature Size: 8\' tall and 3\' to 4\' wide\nBloom Color: Orange\nEvergreen or Deciduous: Deciduous', '1 live starter plant that is 3\" - 6\" tall and growing quickly in a quart pot! This is another beautiful climbing Rose that is very robust and winter-hardy! In Spring, it starts blooming with fragrant flowers that are ora...', '[\"Continuous Blooms\",\"Reblooming Rose\",\"Showy Flowers\",\"Cut Flowers\",\"Repeat Bloomer\",\"Heirloom Rose\",\"Large Flowers\",\"Flowering Hedge\",\"Medium Climber\",\"Fast Growing\",\"Fragrant\",\"Arbor Rose\",\"Full Sun\"]', 1, 1, NULL, NULL, NULL, NULL, 1, 7, 5, 1, 0, 5, '2026-06-24 16:08:57', '2026-06-24 16:08:57'),
(275, 'Astilbe x arendsii \'Bridal Veil\' Live Plant Perennial White Flowers Shade Garden---Beautiful!!', 'astilbe-x-arendsii-bridal-veil-live-plant-perennial-white-flowers-shade-garden-beautiful', 'ETSY-0003', 'simple', 8, NULL, 'Shade Perennials', 23.85, NULL, 14.31, NULL, 'https://i.etsystatic.com/20088520/r/il/77f2e8/3982145656/il_fullxfull.3982145656_eywu.jpg', 'WE CANNOT SHIP TO THE FOLLOWING STATES DUE TO SHIPPING RESTRICTIONS: CALIFORNIA, OREGON, WASHINGTON, ARIZONA, ALASKA, HAWAII, IDAHO AND NEVADA\n**WE CANNOT SHIP TO P.O. BOXES!!**\nSECOND PICTURE IS A REPRESENTATION OF THE PLANT YOU WILL RECEIVE.\n***ITEMS ARE TAPED IN THE BOX FOR SECURE SHIPPING. PLEASE BE CAREFUL TO REMOVE TAPE FIRST BEFORE REMOVING PLANT(S)***\n\nThis listing is for a live plant that is 6\" to 8\" tall. This gorgeous variety has vivid green foliage and pure white upright flowers in Summer. These plants are great to brighten up shady spots in your garden and look fantastic paired up with other different colored Astilbes! Add these beauties to your collection!!\n\nCommon Name: \'Bridal Veil\' Astilbe\nBotanical Name: Astilbe x arendsii\nHardiness Zones: 4 - 9\nSunlight: Full shade/part shade\nSoil Requirements: Moist, well drained soil\nMature Size: 1\' to 3\' tall and 3\' wide\nDeciduous or Evergreen: Dies back in Winter and grows back from the roots in Spring', 'a live plant that is 6\" to 8\" tall.', '[\"Low Maintenance\",\"Cottage Garden\",\"Summer Flowers\",\"Shade Garden\",\"Cut Flowers\",\"Cutting Garden\",\"Woodland Garden\",\"Mass Planting\",\"Attracts Butterflies\",\"Shade Lover\",\"Moonlight Garden\",\"Showy Flowers\",\"Easy To Grow\"]', 1, 1, NULL, NULL, NULL, NULL, 1, 4, 5, 1, 0, 5, '2026-06-24 16:08:58', '2026-06-24 16:08:58'),
