(3211, 348, 197, NULL, 5, NULL, 'Some varieties of Japanese maples are more difficult to locate at nurseries but I found this rare tree at this outstanding nursery.  I look forward to purchasing more trees from this seller as the trees are healthy and happy and arrived safe and secure.  Thank YOU.', 'delivery_packaging', 5, 5, 5, NULL, NULL, '[]', 1, 0, 'approved', '2024-06-19 16:19:40', '2024-06-19 16:19:40'),
(3212, 290, 197, NULL, 5, NULL, 'I am so happy to have found this outstanding nursery.  The trees have well established grafts and arrive on time and are very healthy.  The packaging is exceptional and I look forward to purchasing many trees from this wonderful seller.', 'delivery_packaging', 5, 5, 5, NULL, NULL, '[]', 1, 0, 'approved', '2024-06-19 16:19:40', '2024-06-19 16:19:40'),
